),
"Coverage: Payer Type" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'type') AS "type" FROM resources r WHERE r.resourceType = 'Coverage' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.114222.4.11.3591')
),
"CQMCommon.Inpatient Encounter" AS (
SELECT * FROM "Encounter: Encounter Inpatient" AS EncounterInpatient WHERE EncounterInpatient.status = 'finished' AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(EncounterInpatient.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) BETWEEN CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Benzodiazepine At Discharge" AS (
SELECT * FROM "MedicationRequest: Schedule IV Benzodiazepines" AS BenzoMedications WHERE (fhirpath_bool(BenzoMedications.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''community'').exists()') OR fhirpath_bool(BenzoMedications.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''discharge'').exists()')) AND array_contains(['active', 'completed'], BenzoMedications.status) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], BenzoMedications.intent)
),
"Inpatient Encounter With Age Greater Than Or Equal To 18" AS (
SELECT * FROM "CQMCommon.Inpatient Encounter" AS InpatientHospitalEncounter WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientHospitalEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = InpatientHospitalEncounter.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientHospitalEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = InpatientHospitalEncounter.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientHospitalEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = InpatientHospitalEncounter.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientHospitalEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = InpatientHospitalEncounter.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 18
),
"Intervention Palliative Or Hospice Care" AS (
(SELECT patient_id, resource FROM "ServiceRequest: Palliative or Hospice Care" AS PalliativeOrHospiceCareOrder WHERE array_contains(['active', 'completed', 'on-hold'], PalliativeOrHospiceCareOrder.status)) UNION (SELECT patient_id, resource FROM "Procedure: Palliative or Hospice Care" AS PalliativeOrHospiceCarePerformed WHERE array_contains(['completed', 'in-progress'], PalliativeOrHospiceCarePerformed.status))
),
"Medications For Opioid Use Disorder" AS (
SELECT * FROM "MedicationRequest: Medications for Opioid Use Disorder (MOUD)" AS DischargeMedication WHERE (fhirpath_bool(DischargeMedication.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''community'').exists()') OR fhirpath_bool(DischargeMedication.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''discharge'').exists()')) AND array_contains(['active', 'completed'], DischargeMedication.status) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], DischargeMedication.intent)
),
"Opioid At Discharge" AS (
SELECT * FROM "MedicationRequest: Schedule II, III and IV Opioid Medications" AS OpioidMedications WHERE (fhirpath_bool(OpioidMedications.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''community'').exists()') OR fhirpath_bool(OpioidMedications.resource, 'category.coding.where(system=''http://terminology.hl7.org/CodeSystem/medicationrequest-category'' and code=''discharge'').exists()')) AND array_contains(['active', 'completed'], OpioidMedications.status) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], OpioidMedications.intent)
),
"Inpatient Encounters With An Opioid Or Benzodiazepine At Discharge" AS (
SELECT * FROM "Inpatient Encounter With Age Greater Than Or Equal To 18" AS InpatientEncounter WHERE EXISTS (SELECT 1 FROM ((SELECT patient_id, resource FROM "Opioid At Discharge") UNION (SELECT patient_id, resource FROM "Benzodiazepine At Discharge")) AS OpioidOrBenzodiazepineAtDischarge WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidOrBenzodiazepineAtDischarge.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidOrBenzodiazepineAtDischarge.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND OpioidOrBenzodiazepineAtDischarge.patient_id = InpatientEncounter.patient_id)
),
"Initial Population" AS (
SELECT * FROM "Inpatient Encounters With An Opioid Or Benzodiazepine At Discharge"
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Inpatient Encounter With Encounter Diagnosis Of Cancer Pain" AS (
SELECT * FROM "Denominator" AS QualifyingEncounter WHERE in_valueset(QualifyingEncounter.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1111.180') OR EXISTS (SELECT 1 FROM (SELECT unnest((SELECT list(CASE WHEN (SELECT COUNT(*) FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = QualifyingEncounter.patient_id) = 1 THEN (SELECT resource FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = QualifyingEncounter.patient_id LIMIT 1) ELSE NULL END) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounter.resource, 'reasonReference'), '["VARCHAR"]')) AS _lt_D) AS _lt_unnest)) AS _ivr) AS _ivt WHERE in_valueset(_ivr, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1111.180'))
),
"Numerator" AS (
SELECT * FROM "Denominator" AS InpatientEncounter WHERE (SELECT COUNT(_val) FROM (SELECT DISTINCT fhirpath_text(OpioidMedications.resource, 'medication') AS _val FROM "Opioid At Discharge" AS OpioidMedications WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidMedications.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidMedications.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND OpioidMedications.patient_id = InpatientEncounter.patient_id) AS _agg) >= 2 OR EXISTS (SELECT * FROM "Opioid At Discharge" AS OpioidDischargeMedications WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidDischargeMedications.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(OpioidDischargeMedications.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND EXISTS (SELECT * FROM "Benzodiazepine At Discharge" AS BenzodiazepineDischargeMedication WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(BenzodiazepineDischargeMedication.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(BenzodiazepineDischargeMedication.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND BenzodiazepineDischargeMedication.patient_id = InpatientEncounter.patient_id) AND OpioidDischargeMedications.patient_id = InpatientEncounter.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
